import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote — empty and basic items
  it.todo("empty item list yields premium of 5 G (processing fee only)");
  it.todo("a single plain sword yields premium of 115 G (100 base + 10 first insurance + 5 fee)");
  it.todo("a single plain amulet yields premium of 71 G (60 + 6 + 5)");
  it.todo("a single plain staff yields premium of 93 G (80 + 8 + 5)");
  it.todo("a single plain potion yields premium of 49 G (40 + 4 + 5)");

  // Components and building blocks
  it.todo("a single rune component yields premium of 33 G (25 + 3 + 5)");
  it.todo("two runes yield premium of 60 G (50 + 5 + 5)");
  it.todo("three alike runes form a block: premium 71 G (60 + 6 + 5)");
  it.todo("four runes: no block, premium 115 G (100 + 10 + 5)");
  it.todo("two runes + one moonstone: no block, premium 88 G (75 + 7.5→8 + 5)");
  it.todo("three runes + three moonstones: two blocks, premium 137 G (120 + 12 + 5)");

  // Per-item modifiers
  it.todo("a cursed sword (newcomer): premium 165 G");
  it.todo("a sword with enchantment 5 adds 30% surcharge");
  it.todo("a sword with enchantment 4 adds no surcharge");
  it.todo("a cursed sword with enchantment 5 stacks both surcharges");

  // Policy-wide modifiers
  it.todo("loyalty discount (≥2 years) applies to policy base premium");
  it.todo("loyalty discount at exactly 2 years applies");
  it.todo("follow-up contract applies 15% discount after first quote");
  it.todo("multi-item policy: cursed surcharge applies only to cursed item's base premium");

  // Rounding
  it.todo("premium rounds up (in MHPCO's favor)");

  // Claims — basic
  it.todo("standard claim on plain sword: 500 damage → payout 400, cap depletes by 400");
  it.todo("claim on rune (no enchantment/material): 200 damage → payout 100");
  it.todo("high-enchantment item (≥8): 50% reimbursement, then deductible");
  it.todo("dragon-material item: full reimbursement, then deductible");
  it.todo("high enchantment + dragon material: 50% rule wins, then deductible");
  it.todo("deductible applies per damage entry (multiple items damaged)");

  // Cap and multi-item
  it.todo("policy cap is 2× insurance sum");
  it.todo("two-claim scenario: cap depletes across claims");
  it.todo("multiple items of same type: each damage entry has its own deductible");

  // Errors
  it.todo("unknown item type in quote → CLI exits non-zero");
  it.todo("claim references item not on policy → CLI exits non-zero");
  it.todo("damage with negative amount → CLI exits non-zero");
  it.todo("too many damage entries of a given type → CLI exits non-zero");

  // Integration
  it.todo("newcomer with cursed sword: 165 G");
  it.todo("long-standing customer's second contract with cursed enchanted sword: 160 G");
});

