type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Customer = { yearsWithMHPCO: number };
type Scenario = { customer: Customer; steps: Step[] };
type QuoteResult = { premium: number };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const quoteStep = (step: Step): QuoteResult => {
  const itemsBase = step.items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
  const premium = Math.ceil(itemsBase + firstInsurance) + PROCESSING_FEE;
  return { premium };
};

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  const results = scenario.steps.map(quoteStep);
  return { results };
};

