type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Customer = { yearsWithMHPCO: number };
type Scenario = { customer: Customer; steps: Step[] };
type QuoteResult = { premium: number };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const COMPONENT_BASE_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const isComponent = (item: Item): boolean => BASE_PREMIUMS[item.type] === undefined;

const componentGroupBase = (count: number): number =>
  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * COMPONENT_BASE_PREMIUM;

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
    new Map<string, number>(),
  );

const itemsBaseTotal = (items: Item[]): number => {
  const mainItemsBase = items
    .filter((i) => !isComponent(i))
    .reduce((sum, i) => sum + BASE_PREMIUMS[i.type], 0);

  const componentsBase = [...countByType(items.filter(isComponent)).values()]
    .reduce((sum, count) => sum + componentGroupBase(count), 0);

  return mainItemsBase + componentsBase;
};

const quoteStep = (step: Step): QuoteResult => {
  const itemsBase = itemsBaseTotal(step.items);
  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
  const premium = Math.ceil(itemsBase + firstInsurance) + PROCESSING_FEE;
  return { premium };
};

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  const results = scenario.steps.map(quoteStep);
  return { results };
};

