const componentGroupBase = (count: number): number =>
  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * COMPONENT_BASE_PREMIUM;

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
    new Map<string, number>(),
  );

// Returns base premium attributed to a single main item (not components).
const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];

// Components are priced per group with block discount.
const componentsBaseTotal = (components: Item[]): number =>
  [...countByType(components).values()].reduce(
    (sum, count) => sum + componentGroupBase(count),
    0,
  );

// Base premium of the whole policy (raw, no item modifiers).
const policyBase = (items: Item[]): number => {
  const mainBase = items.filter((i) => !isComponent(i)).reduce((sum, i) => sum + itemBasePremium(i), 0);
  const compBase = componentsBaseTotal(items.filter(isComponent));
  return mainBase + compBase;
};

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

// Surcharges that apply to a single item's base premium (cursed, high enchantment).
const itemSurcharge = (item: Item): number => {
  if (isComponent(item)) return 0;
  const base = itemBasePremium(item);
  const rate = (isCursed(item) ? CURSE_RATE : 0) + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
  return base * rate;
};

const itemSurchargesTotal = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemSurcharge(item), 0);

const quoteStep = (step: Step): QuoteResult => {
  const base = policyBase(step.items);
  const itemSurcharges = itemSurchargesTotal(step.items);
  const firstInsurance = base * FIRST_INSURANCE_RATE;
  const premium = Math.ceil(base + itemSurcharges + firstInsurance) + PROCESSING_FEE;
  return { premium };
};

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  const results = scenario.steps.map(quoteStep);
  return { results };
};

